import React, { useEffect, useState } from "react";
import Repository from "./Repository";
import {
  PieChart, Pie, Cell,
  BarChart, Bar, XAxis, YAxis, Tooltip, Legend
} from "recharts";
import "./Repositories.css";


const token = "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";

const COLORS = ["#4da6ff", "#339966", "#ff9933", "#ff6666", "#9966ff", "#66cccc"];

export default function Repositories() {
  const [repos, setRepos] = useState([]);
  const [langData, setLangData] = useState([]);
  const [updateData, setUpdateData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const username = "unix69"; // cambia con l'username GitHub reale
  const controller = new AbortController(); // per eventuali cancel fetch

  useEffect(() => {
    async function fetchRepos() {
      try {
        const fetchedRepos = await Repository.fetchAllByUsername(username, controller.signal);
        setRepos(fetchedRepos);
        computeLanguageStats(fetchedRepos);
        computeUpdateTimeline(fetchedRepos);
      } catch (err) {
        console.error("Errore fetch repository:", err);
      } finally {
        setLoading(false);
      }
    }

    fetchRepos();

    return () => controller.abort(); // cleanup
  }, []);

  // Linguaggi più usati
  const computeLanguageStats = (repos) => {
    const langCounts = {};
    repos.forEach(repo => repo.languages.forEach(lang => {
      langCounts[lang] = (langCounts[lang] || 0) + 1;
    }));
    const data = Object.keys(langCounts).map(lang => ({
      name: lang,
      value: langCounts[lang]
    }));
    setLangData(data);
  };

  // Timeline aggiornamenti
  const computeUpdateTimeline = (repos) => {
    const timeline = {};
    repos.forEach(repo => {
      const month = repo.lastUpdate.toISOString().slice(0, 7);
      timeline[month] = (timeline[month] || 0) + 1;
    });
    const data = Object.keys(timeline).sort().map(month => ({
      month,
      updates: timeline[month]
    }));
    setUpdateData(data);
  };

  // filtra repo per ricerca
  const filteredRepos = repos.filter(r => r.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <main className="repositories">
      <h1>Repositories Overview</h1>

      <section className="intro-section">
        <p>
          Questa pagina mostra le repository del tuo account GitHub,
          con statistiche sui linguaggi, attività di aggiornamento e metadati principali.
        </p>
      </section>

      <section className="search-section">
        <input
          type="text"
          placeholder="Cerca repository..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </section>

      {loading && <p style={{textAlign:"center"}}>Caricamento repository...</p>}

      {!loading && filteredRepos.length > 0 && (
        <>
          <section className="repos-summary">
            <h2 className="blue-title">Elenco repository</h2>
            <div className="repo-names">
              {filteredRepos.map(r => (
                <span key={r.id} className="repo-name-pill">{r.name}</span>
              ))}
            </div>
            <p>
              Totale repository: {filteredRepos.length} | 
              Stars totali: {filteredRepos.reduce((sum,r)=>sum+r.stars,0)} | 
              Forks totali: {filteredRepos.reduce((sum,r)=>sum+r.forks,0)} | 
              Media stars/repo: {(filteredRepos.reduce((sum,r)=>sum+r.stars,0)/filteredRepos.length).toFixed(2)} | 
              Media forks/repo: {(filteredRepos.reduce((sum,r)=>sum+r.forks,0)/filteredRepos.length).toFixed(2)}
            </p>
          </section>

          <section className="charts-section">
            <div className="chart-wrapper">
              <h2 className="orange-title">Linguaggi più usati</h2>
              <PieChart width={400} height={300}>
                <Pie
                  data={langData}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={100}
                  label
                >
                  {langData.map((entry,index) => (
                    <Cell key={index} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Legend />
              </PieChart>
            </div>

            <div className="chart-wrapper">
              <h2 className="blue-title">Attività aggiornamenti</h2>
              <BarChart width={500} height={300} data={updateData}>
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="updates" fill="#3399ff" />
              </BarChart>
            </div>
          </section>


          <section className="top-repos">
            <h2 className="blue-title">Top repository</h2>
            <div className="repo-cards">
              {filteredRepos
                .sort((a,b)=>b.stars-a.stars)
                .slice(0,5)
                .map(r => r.renderCard())}
            </div>
          </section>

          <section className="repo-topics-section">
            <h2 className="orange-title">Argomenti principali</h2>
            {filteredRepos.map(r => (
              <div key={r.id} className="repo-topics">
                <strong>{r.name}</strong>:
                {r.topics && r.topics.length > 0 ? r.topics.map(t => (
                  <span key={t} className="topic-pill">{t}</span>
                )) : <span>Nessun topic</span>}
              </div>
            ))}
          </section>
        </>
      )}

      {!loading && filteredRepos.length === 0 && (
        <p style={{textAlign:"center"}}>Nessuna repository trovata.</p>
      )}
    </main>
  );
}
